294	        &self,
295	        /// The pattern to search for.
296	        pattern: StrPattern,
297	    ) -> bool {
298	        match pattern {
299	            StrPattern::Str(pat) => self.0.contains(pat.as_str()),
300	            StrPattern::Regex(re) => re.is_match(self),
