307	        &self,
308	        /// The pattern the string might start with.
309	        pattern: StrPattern,
310	    ) -> bool {
311	        match pattern {
312	            StrPattern::Str(pat) => self.0.starts_with(pat.as_str()),
313	            StrPattern::Regex(re) => re.find(self).is_some_and(|m| m.start() == 0),
