317	    /// Whether the string ends with the specified pattern.
318	    #[func]
319	    pub fn ends_with(
320	        &self,
321	        /// The pattern the string might end with.
322	        pattern: StrPattern,
323	    ) -> bool {
324	        match pattern {
325	            StrPattern::Str(pat) => self.0.ends_with(pat.as_str()),
326	            StrPattern::Regex(re) => {
327	                let mut start_byte = 0;
328	                while let Some(mat) = re.find_at(self, start_byte) {
329	                    if mat.end() == self.0.len() {
330	                        return true;
331	                    }
332	
333	                    // There might still be a match overlapping this one, so
334	                    // restart at the next code point.
335	                    let Some(c) = self[mat.start()..].chars().next() else { break };
336	                    start_byte = mat.start() + c.len_utf8();
337	                }
338	                false
339	            }
340	        }
341	    }
