402	        &self,
403	        /// The pattern to search for.
404	        pattern: StrPattern,
405	    ) -> Array {
406	        match pattern {
407	            StrPattern::Str(pat) => self
408	                .0
409	                .match_indices(pat.as_str())
410	                .map(match_to_dict)
411	                .map(Value::Dict)
412	                .collect(),
413	            StrPattern::Regex(re) => re
