421	    /// Replace at most `count` occurrences of the given pattern with a
422	    /// replacement string or function (beginning from the start). If no count
423	    /// is given, all occurrences are replaced.
424	    #[func]
425	    pub fn replace(
426	        &self,
427	        /// The engine.
428	        engine: &mut Engine,
429	        /// The callsite context.
430	        context: Tracked<Context>,
431	        /// The pattern to search for.
432	        pattern: StrPattern,
433	        /// The string to replace the matches with or a function that gets a
434	        /// dictionary for each match and can return individual replacement
435	        /// strings.
436	        replacement: Replacement,
437	        ///  If given, only the first `count` matches of the pattern are placed.
438	        #[named]
439	        count: Option<usize>,
440	    ) -> SourceResult<Str> {
441	        // Heuristic: Assume the new string is about the same length as
442	        // the current string.
443	        let mut output = EcoString::with_capacity(self.as_str().len());
444	
445	        // Replace one match of a pattern with the replacement.
446	        let mut last_match = 0;
447	        let mut handle_match = |range: Range<usize>, dict: Dict| -> SourceResult<()> {
448	            // Push everything until the match.
449	            output.push_str(&self[last_match..range.start]);
450	            last_match = range.end;
451	
452	            // Determine and push the replacement.
453	            match &replacement {
454	                Replacement::Str(s) => output.push_str(s),
455	                Replacement::Func(func) => {
456	                    let piece = func
457	                        .call(engine, context, [dict])?
458	                        .cast::<Str>()
459	                        .at(func.span())?;
460	                    output.push_str(&piece);
461	                }
462	            }
463	
464	            Ok(())
465	        };
466	
467	        // Iterate over the matches of the `pattern`.
468	        let count = count.unwrap_or(usize::MAX);
469	        match &pattern {
470	            StrPattern::Str(pat) => {
471	                for m in self.match_indices(pat.as_str()).take(count) {
472	                    let (start, text) = m;
473	                    handle_match(start..start + text.len(), match_to_dict(m))?;
474	                }
475	            }
476	            StrPattern::Regex(re) => {
477	                for caps in re.captures_iter(self).take(count) {
478	                    // Extract the entire match over all capture groups.
479	                    let m = caps.get(0).unwrap();
480	                    handle_match(m.start()..m.end(), captures_to_dict(caps))?;
481	                }
482	            }
483	        }
484	
485	        // Push the remainder.
486	        output.push_str(&self[last_match..]);
487	        Ok(output.into())
488	    }
