490	    /// Removes matches of a pattern from one or both sides of the string, once or
491	    /// repeatedly and returns the resulting string.
492	    #[func]
493	    pub fn trim(
494	        &self,
495	        /// The pattern to search for. If `{none}`, trims white spaces.
496	        #[default]
497	        pattern: Option<StrPattern>,
498	        /// Can be `{start}` or `{end}` to only trim the start or end of the
499	        /// string. If omitted, both sides are trimmed.
500	        #[named]
501	        at: Option<StrSide>,
502	        /// Whether to repeatedly removes matches of the pattern or just once.
503	        /// Defaults to `{true}`.
504	        #[named]
505	        #[default(true)]
506	        repeat: bool,
507	    ) -> Str {
508	        let mut start = matches!(at, Some(StrSide::Start) | None);
509	        let end = matches!(at, Some(StrSide::End) | None);
510	
511	        let trimmed = match pattern {
512	            None => match at {
513	                None => self.0.trim(),
514	                Some(StrSide::Start) => self.0.trim_start(),
515	                Some(StrSide::End) => self.0.trim_end(),
516	            },
517	            Some(StrPattern::Str(pat)) => {
518	                let pat = pat.as_str();
519	                let mut s = self.as_str();
520	                if repeat {
521	                    if start {
522	                        s = s.trim_start_matches(pat);
523	                    }
524	                    if end {
525	                        s = s.trim_end_matches(pat);
526	                    }
527	                } else {
528	                    if start {
529	                        s = s.strip_prefix(pat).unwrap_or(s);
530	                    }
531	                    if end {
532	                        s = s.strip_suffix(pat).unwrap_or(s);
533	                    }
534	                }
535	                s
536	            }
537	            Some(StrPattern::Regex(re)) => {
538	                let s = self.as_str();
539	                let mut last = None;
540	                let mut range = 0..s.len();
541	
542	                for m in re.find_iter(s) {
543	                    // Does this match follow directly after the last one?
544	                    let consecutive = last == Some(m.start());
545	
546	                    // As long as we're at the beginning or in a consecutive run
547	                    // of matches, and we're still trimming at the start, trim.
548	                    start &= m.start() == 0 || consecutive;
549	                    if start {
550	                        range.start = m.end();
551	                        start &= repeat;
552	                    }
553	
554	                    // Reset end trim if we aren't consecutive anymore or aren't
555	                    // repeating.
556	                    if end && (!consecutive || !repeat) {
557	                        range.end = m.start();
558	                    }
559	
560	                    last = Some(m.end());
561	                }
562	
563	                // Is the last match directly at the end?
564	                if last.is_some_and(|last| last < s.len()) {
565	                    range.end = s.len();
566	                }
567	
568	                &s[range.start..range.start.max(range.end)]
569	            }
570	        };
571	
572	        trimmed.into()
573	    }
