/// Extracts the first grapheme cluster of the string.
/// Fails with an error if the string is empty.
#[func]
pub fn first(
    &self,
    /// Number of times to repeat this operation. Fails if exceeds string
    /// length.
    #[named]
    #[default(1)]
    repeat: usize,
) -> StrResult<Str> {
    let mut result = EcoString::new();
    let mut count = 0;
    for grapheme in self.0.graphemes(true) {
        if count == repeat {
            break;
        }
        result.push_str(grapheme);
        count += 1;
    }
    if count < repeat {
        return Err(if self.0.is_empty() {
            string_is_empty()
        } else {
            not_enough_graphemes(repeat)
        });
    }
    Ok(result.into())
}

/// Extracts the last grapheme cluster of the string.
/// Fails with an error if the string is empty.
#[func]
pub fn last(
    &self,
    /// Number of times to repeat this operation. Fails if exceeds string
    /// length.
    #[named]
    #[default(1)]
    repeat: usize,
) -> StrResult<Str> {
    let mut graphemes = Vec::with_capacity(repeat);
    for grapheme in self.0.graphemes(true).rev() {
        if graphemes.len() == repeat {
            break;
        }
        graphemes.push(grapheme);
    }
    if graphemes.len() < repeat {
        return Err(if self.0.is_empty() {
            string_is_empty()
        } else {
            not_enough_graphemes(repeat)
        });
    }

